function schedule(address account, bytes32 salt, bytes32 mode, bytes calldata data) public virtual {
    require(_config[account].installed, ERC7579ExecutorModuleNotInstalled());
    _validateSchedule(account, salt, mode, data);
    (uint32 executableAfter, , ) = getDelay(account);
    _scheduleAt(account, salt, mode, data, Time.timestamp(), executableAfter);
}

function _validateStateBitmap(bytes32 operationId, bytes32 allowedStates) internal view returns (OperationState) {
    OperationState currentState = state(operationId);
    require(
        _encodeStateBitmap(currentState) & allowedStates != bytes32(0),
        ERC7579ExecutorUnexpectedOperationState(operationId, currentState, allowedStates)
    );
    return currentState;
}

function _rawERC7579Validation(
    address account,
    bytes32 hash,
    bytes calldata signature
) internal view virtual override returns (bool) {
    (bytes[] memory signingSigners, bytes[] memory signatures) = abi.decode(signature, (bytes[], bytes[]));
    return
        _validateThreshold(account, signingSigners) &&
        _validateSignatures(account, hash, signingSigners, signatures);
}

function _removeSigners(address account, bytes[] memory oldSigners) internal virtual {
    for (uint256 i = 0; i < oldSigners.length; ++i) {
        bytes memory signer = oldSigners[i];
        require(_signersSetByAccount[account].remove(signer), ERC7579MultisigNonexistentSigner(signer));
        emit ERC7913SignerRemoved(account, signer);
    }
    _validateReachableThreshold(account);
}

function registerChainEquivalence(uint256 chainId, uint16 wormholeId) public virtual onlyOwner {
    require(
        _chainIdToWormhole[chainId] == 0 && _wormholeToChainId[wormholeId] == 0,
        ChainEquivalenceAlreadyRegistered(chainId, wormholeId)
    );

    _chainIdToWormhole[chainId] = wormholeId | EVM_ID_FLAG;
    _wormholeToChainId[wormholeId] = chainId;
    emit RegisteredChainEquivalence(chainId, wormholeId);
}

function operations(uint256 start, uint256 end) public view returns (Operation[] memory operations_) {
    if (start > end || start >= _operationsIdSet.length()) {
        revert InvalidIndexRange(start, end);
    }
    operations_ = new Operation[](end - start);
    for (uint256 i = start; i < end; i++) {
        operations_[i] = _operationsMap[_operationsIdSet.at(i)];
    }
    return operations_;
}

function operationsBatch(
    uint256 start,
    uint256 end
) public view returns (OperationBatch[] memory operationsBatch_) {
    if (start > end || start >= _operationsBatchIdSet.length()) {
        revert InvalidIndexRange(start, end);
    }
    operationsBatch_ = new OperationBatch[](end - start);
    for (uint256 i = start; i < end; i++) {
        operationsBatch_[i] = _operationsBatchMap[_operationsBatchIdSet.at(i)];
    }
    return operationsBatch_;
}

function validateContractCall(
    bytes32 commandId,
    string calldata sourceChain,
    string calldata sourceAddress,
    bytes32 payloadHash
) external returns (bool) {
    if (_pendingCommandIds.get(uint256(commandId))) {
        _pendingCommandIds.unset(uint256(commandId));

        emit IBaseAmplifierGateway.MessageExecuted(commandId);

        return
            commandId ==
            keccak256(abi.encode(sourceChain, sourceAddress, msg.sender.toChecksumHexString(), payloadHash));
    } else return false;
}

function _update(address from, address to, uint256 value) internal virtual override {
    if (from != address(0)) {
        uint256 unfrozen = available(from);
        require(unfrozen >= value, ERC20InsufficientUnfrozenBalance(from, value, unfrozen));
    }
    super._update(from, to, value);
}

function _deposit(address caller, address receiver, uint256 assets, uint256 shares) internal virtual override {
    uint256 fee = _feeOnTotal(assets, _entryFeeBasisPoints());
    address recipient = _entryFeeRecipient();

    super._deposit(caller, receiver, assets, shares);

    if (fee > 0 && recipient != address(this)) {
        SafeERC20.safeTransfer(IERC20(asset()), recipient, fee);
    }
}

function _withdraw(
    address caller,
    address receiver,
    address owner,
    uint256 assets,
    uint256 shares
) internal virtual override {
    uint256 fee = _feeOnRaw(assets, _exitFeeBasisPoints());
    address recipient = _exitFeeRecipient();

    super._withdraw(caller, receiver, owner, assets, shares);

    if (fee > 0 && recipient != address(this)) {
        SafeERC20.safeTransfer(IERC20(asset()), recipient, fee);
    }
}

function _pendingDepositRequest(
    uint256 requestId,
    address controller
) internal view virtual override returns (uint256) {
    unchecked {
        uint48 timepoint = requestId.toUint48();
        return
            timepoint > clock()
                ? _readyDepositAt(controller, timepoint) - _readyDepositAt(controller, timepoint - 1)
                : 0;
    }
}

function _claimableDepositRequest(
    uint256 requestId,
    address controller
) internal view virtual override returns (uint256) {
    unchecked {
        uint48 timepoint = requestId.toUint48();
        return
            (timepoint == 0 || timepoint > clock())
                ? 0
                : _readyDepositAt(controller, timepoint) - _readyDepositAt(controller, timepoint - 1);
    }
}

function _claimableRedeemRequest(
    uint256 requestId,
    address controller
) internal view virtual override returns (uint256) {
    unchecked {
        uint48 timepoint = requestId.toUint48();
        return
            (timepoint == 0 || timepoint > clock())
                ? 0
                : _readyRedeemAt(controller, timepoint) - _readyRedeemAt(controller, timepoint - 1);
    }
}

function values(Bytes32x2Set storage set, uint256 start, uint256 end) internal view returns (bytes32[2][] memory) {
    unchecked {
        end = Math.min(end, length(set));
        start = Math.min(start, end);

        uint256 len = end - start;
        bytes32[2][] memory result = new bytes32[2][](len);
        for (uint256 i = 0; i < len; ++i) {
            result[i] = set._values[start + i];
        }
        return result;
    }
}

function __AccessControlDefaultAdminRules_init_unchained(uint48 initialDelay, address initialDefaultAdmin) internal onlyInitializing {
    AccessControlDefaultAdminRulesStorage storage $ = _getAccessControlDefaultAdminRulesStorage();
    if (initialDefaultAdmin == address(0)) {
        revert AccessControlInvalidDefaultAdmin(address(0));
    }
    $._currentDelay = initialDelay;
    _grantRole(DEFAULT_ADMIN_ROLE, initialDefaultAdmin);
}

function grantRole(bytes32 role, address account) public virtual override(AccessControlUpgradeable, IAccessControl) {
    if (role == DEFAULT_ADMIN_ROLE) {
        revert AccessControlEnforcedDefaultAdminRules();
    }
    super.grantRole(role, account);
}

function revokeRole(bytes32 role, address account) public virtual override(AccessControlUpgradeable, IAccessControl) {
    if (role == DEFAULT_ADMIN_ROLE) {
        revert AccessControlEnforcedDefaultAdminRules();
    }
    super.revokeRole(role, account);
}

function getAccess(
    uint64 roleId,
    address account
) public view virtual returns (uint48 since, uint32 currentDelay, uint32 pendingDelay, uint48 effect) {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    Access storage access = $._roles[roleId].members[account];

    since = access.since;
    (currentDelay, pendingDelay, effect) = access.delay.getFull();

    return (since, currentDelay, pendingDelay, effect);
}

function _setRoleAdmin(uint64 roleId, uint64 admin) internal virtual {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    if (roleId == ADMIN_ROLE || roleId == PUBLIC_ROLE) {
        revert AccessManagerLockedRole(roleId);
    }

    $._roles[roleId].admin = admin;

    emit RoleAdminChanged(roleId, admin);
}

function _setRoleGuardian(uint64 roleId, uint64 guardian) internal virtual {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    if (roleId == ADMIN_ROLE || roleId == PUBLIC_ROLE) {
        revert AccessManagerLockedRole(roleId);
    }

    $._roles[roleId].guardian = guardian;

    emit RoleGuardianChanged(roleId, guardian);
}

function _checkNotScheduled(bytes32 operationId) private view {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    uint48 prevTimepoint = $._schedules[operationId].timepoint;
    if (prevTimepoint != 0 && !_isExpired(prevTimepoint)) {
        revert AccessManagerAlreadyScheduled(operationId);
    }
}

function _installModule(
    uint256 moduleTypeId,
    address module,
    bytes memory initData
) internal virtual override withHook {
    AccountERC7579HookedStorage storage $ = _getAccountERC7579HookedStorage();
    if (moduleTypeId == MODULE_TYPE_HOOK) {
        require($._hook == address(0), ERC7579HookModuleAlreadyPresent($._hook));
        $._hook = module;
    }
    super._installModule(moduleTypeId, module, initData);
}

function onERC1155Received(
    address operator,
    address /* from */,
    uint256 /* id */,
    uint256 /* value */,
    bytes memory /* data */
) public virtual override returns (bytes4) {
    BridgeERC1155Storage storage $ = _getBridgeERC1155Storage();
    return
        msg.sender == address($._token) && operator == address(this)
            ? IERC1155Receiver.onERC1155Received.selector
            : bytes4(0);
}

function onERC1155BatchReceived(
    address operator,
    address /* from */,
    uint256[] memory /* ids */,
    uint256[] memory /* values */,
    bytes memory /* data */
) public virtual override returns (bytes4) {
    BridgeERC1155Storage storage $ = _getBridgeERC1155Storage();
    return
        msg.sender == address($._token) && operator == address(this)
            ? IERC1155Receiver.onERC1155BatchReceived.selector
            : bytes4(0);
}

function state(uint256 proposalId) public view virtual override returns (ProposalState) {
    GovernorTimelockCompoundStorage storage $ = _getGovernorTimelockCompoundStorage();
    ProposalState currentState = super.state(proposalId);

    return
        (currentState == ProposalState.Queued &&
            block.timestamp >= proposalEta(proposalId) + $._timelock.GRACE_PERIOD())
            ? ProposalState.Expired
            : currentState;
}

function _executeOperations(
    uint256 proposalId,
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 /*descriptionHash*/
) internal virtual override {
    GovernorTimelockCompoundStorage storage $ = _getGovernorTimelockCompoundStorage();
    uint256 etaSeconds = proposalEta(proposalId);
    Address.sendValue(payable($._timelock), msg.value);
    for (uint256 i = 0; i < targets.length; ++i) {
        $._timelock.executeTransaction(targets[i], values[i], "", calldatas[i], etaSeconds);
    }
}

function supportsInterface(bytes4 interfaceId) public view virtual override(IERC165, ERC165Upgradeable) returns (bool) {
    return
        interfaceId == type(IGovernor).interfaceId ||
        interfaceId == type(IGovernor).interfaceId ^ IGovernor.getProposalId.selector ||
        interfaceId == type(IERC1155Receiver).interfaceId ||
        super.supportsInterface(interfaceId);
}

function _checkGovernance() internal virtual {
    GovernorStorage storage $ = _getGovernorStorage();
    if (_executor() != _msgSender()) {
        revert GovernorOnlyExecutor(_msgSender());
    }
    if (_executor() != address(this)) {
        bytes32 msgDataHash = keccak256(_msgData());
        // loop until popping the expected operation - throw if deque is empty (operation not authorized)
        while ($._governanceCall.popFront() != msgDataHash) {}
    }
}

function _transferVotingUnits(address from, address to, uint256 amount) internal virtual {
    VotesStorage storage $ = _getVotesStorage();
    if (from == address(0)) {
        _push($._totalCheckpoints, _add, SafeCast.toUint208(amount));
    }
    if (to == address(0)) {
        _push($._totalCheckpoints, _subtract, SafeCast.toUint208(amount));
    }
    _moveDelegateVotes(delegates(from), delegates(to), amount);
}
